import type { SATQuestion } from './types'

// SAT R&W Batch 6 - Mixed Reading & Writing (120 questions)
export const rwBatch6: SATQuestion[] = [
  { id: 'sat_rw_b6_001', category: 'reading', subcategory: 'vocabulary', difficulty: 'easy', passage: 'The teacher\'s ________ instructions made the assignment easy for every student to understand.', question: 'Which word best completes the text?', options: [{ letter: 'A', text: 'clear' }, { letter: 'B', text: 'ambiguous' }, { letter: 'C', text: 'convoluted' }, { letter: 'D', text: 'obscure' }], correct: 'A', explanation: '"Clear" means easily understood, matching instructions that were easy to follow.' },
  { id: 'sat_rw_b6_002', category: 'writing', subcategory: 'grammar', difficulty: 'easy', passage: 'The flock of birds ________ migrating south for the winter.', question: 'Which choice conforms to Standard English?', options: [{ letter: 'A', text: 'is' }, { letter: 'B', text: 'are' }, { letter: 'C', text: 'were being' }, { letter: 'D', text: 'have been' }], correct: 'A', explanation: '"Flock" is a singular collective noun, so "is" is correct.' },
  { id: 'sat_rw_b6_003', category: 'reading', subcategory: 'vocabulary', difficulty: 'easy', passage: 'After weeks of drought, the farmers were ________ when rain finally arrived.', question: 'Which word best completes the text?', options: [{ letter: 'A', text: 'relieved' }, { letter: 'B', text: 'dismayed' }, { letter: 'C', text: 'indifferent' }, { letter: 'D', text: 'frustrated' }], correct: 'A', explanation: '"Relieved" conveys the positive feeling after a stressful period of drought.' },
  { id: 'sat_rw_b6_004', category: 'writing', subcategory: 'punctuation', difficulty: 'easy', passage: 'The bakery offers three types of bread________ sourdough, rye, and wheat.', question: 'Which punctuation completes the text correctly?', options: [{ letter: 'A', text: ':' }, { letter: 'B', text: ',' }, { letter: 'C', text: ';' }, { letter: 'D', text: '—' }], correct: 'A', explanation: 'A colon introduces a list after a complete sentence.' },
  { id: 'sat_rw_b6_005', category: 'reading', subcategory: 'vocabulary', difficulty: 'easy', passage: 'The new employee was ________ to learn the company\'s procedures, asking questions and taking notes throughout the day.', question: 'Which word best completes the text?', options: [{ letter: 'A', text: 'eager' }, { letter: 'B', text: 'reluctant' }, { letter: 'C', text: 'hesitant' }, { letter: 'D', text: 'apathetic' }], correct: 'A', explanation: '"Eager" means enthusiastic and willing, matching the behavior of asking questions and taking notes.' },
  { id: 'sat_rw_b6_006', category: 'writing', subcategory: 'grammar', difficulty: 'easy', passage: 'She completed the project ________ than anyone else on the team.', question: 'Which choice conforms to Standard English?', options: [{ letter: 'A', text: 'more quickly' }, { letter: 'B', text: 'most quickly' }, { letter: 'C', text: 'quicker' }, { letter: 'D', text: 'quickest' }], correct: 'A', explanation: '"More quickly" is the correct comparative adverb form when comparing two entities.' },
  { id: 'sat_rw_b6_007', category: 'writing', subcategory: 'sentence-structure', difficulty: 'easy', passage: 'The garden was full of flowers. It attracted many butterflies.', question: 'Which choice best combines these sentences?', options: [{ letter: 'A', text: 'The garden, full of flowers, attracted many butterflies.' }, { letter: 'B', text: 'The garden was full of flowers, it attracted many butterflies.' }, { letter: 'C', text: 'Full of flowers and butterflies were attracted to the garden.' }, { letter: 'D', text: 'The garden was full of flowers and attracting butterflies.' }], correct: 'A', explanation: 'Option A concisely combines both ideas using an appositive phrase.' },
  { id: 'sat_rw_b6_008', category: 'reading', subcategory: 'reading-comprehension', difficulty: 'easy', passage: 'Honeybees communicate the location of food sources through a series of movements known as the waggle dance. By varying the angle and duration of the dance, a bee can convey both the direction and distance of a food source relative to the hive.', question: 'What is the main purpose of the waggle dance?', options: [{ letter: 'A', text: 'To share the location of food with other bees' }, { letter: 'B', text: 'To attract a mate during breeding season' }, { letter: 'C', text: 'To warn other bees of predators' }, { letter: 'D', text: 'To establish dominance within the hive' }], correct: 'A', explanation: 'The passage states the dance communicates the location of food sources.' },
  { id: 'sat_rw_b6_009', category: 'writing', subcategory: 'grammar', difficulty: 'easy', passage: 'The dog wagged ________ tail when its owner came home.', question: 'Which choice conforms to Standard English?', options: [{ letter: 'A', text: 'its' }, { letter: 'B', text: "it's" }, { letter: 'C', text: 'their' }, { letter: 'D', text: "they're" }], correct: 'A', explanation: '"Its" is the possessive pronoun. "It\'s" means "it is."' },
  { id: 'sat_rw_b6_010', category: 'reading', subcategory: 'vocabulary', difficulty: 'easy', passage: 'The movie received ________ reviews from critics, who praised its acting, direction, and screenplay.', question: 'Which word best completes the text?', options: [{ letter: 'A', text: 'favorable' }, { letter: 'B', text: 'harsh' }, { letter: 'C', text: 'mixed' }, { letter: 'D', text: 'scathing' }], correct: 'A', explanation: '"Favorable" means positive or approving, consistent with critics who praised the film.' },
  { id: 'sat_rw_b6_011', category: 'writing', subcategory: 'punctuation', difficulty: 'easy', passage: 'The students finished their exams________ they celebrated by going out for dinner.', question: 'Which punctuation completes the text correctly?', options: [{ letter: 'A', text: ';' }, { letter: 'B', text: ',' }, { letter: 'C', text: ':' }, { letter: 'D', text: '.' }], correct: 'A', explanation: 'A semicolon correctly joins two related independent clauses.' },
  { id: 'sat_rw_b6_012', category: 'reading', subcategory: 'vocabulary', difficulty: 'easy', passage: 'The hiker felt ________ after climbing to the summit, sitting down to rest before the descent.', question: 'Which word best completes the text?', options: [{ letter: 'A', text: 'exhausted' }, { letter: 'B', text: 'energized' }, { letter: 'C', text: 'indifferent' }, { letter: 'D', text: 'restless' }], correct: 'A', explanation: '"Exhausted" means extremely tired, fitting someone who needs to rest after a strenuous climb.' },
  { id: 'sat_rw_b6_013', category: 'writing', subcategory: 'grammar', difficulty: 'easy', passage: 'Every student in the class ________ required to submit a final essay.', question: 'Which choice conforms to Standard English?', options: [{ letter: 'A', text: 'is' }, { letter: 'B', text: 'are' }, { letter: 'C', text: 'were' }, { letter: 'D', text: 'have been' }], correct: 'A', explanation: '"Every student" is singular, requiring the singular verb "is."' },
  { id: 'sat_rw_b6_014', category: 'writing', subcategory: 'sentence-structure', difficulty: 'easy', passage: 'Running through the park, ________.', question: 'Which choice correctly completes the sentence?', options: [{ letter: 'A', text: 'she noticed a family of ducks by the pond' }, { letter: 'B', text: 'the pond had a family of ducks' }, { letter: 'C', text: 'a family of ducks was seen' }, { letter: 'D', text: 'it was a beautiful day' }], correct: 'A', explanation: 'The participial phrase "Running through the park" must modify a person—"she."' },
  { id: 'sat_rw_b6_015', category: 'reading', subcategory: 'reading-comprehension', difficulty: 'easy', passage: 'The library has been a cornerstone of the community for over fifty years. It offers free access to books, computers, and educational programs. Last year, the library served more than twenty thousand patrons.', question: 'What is the main idea of the passage?', options: [{ letter: 'A', text: 'The library is an important and well-used community resource' }, { letter: 'B', text: 'The library needs more funding to continue operating' }, { letter: 'C', text: 'Libraries are becoming obsolete in the digital age' }, { letter: 'D', text: 'Most people only visit the library to use computers' }], correct: 'A', explanation: 'The passage describes the library\'s long history, services, and high usage.' },
  { id: 'sat_rw_b6_016', category: 'writing', subcategory: 'grammar', difficulty: 'easy', passage: 'The children played ________ in the snow all afternoon.', question: 'Which choice conforms to Standard English?', options: [{ letter: 'A', text: 'joyfully' }, { letter: 'B', text: 'joyful' }, { letter: 'C', text: 'joy' }, { letter: 'D', text: 'joyed' }], correct: 'A', explanation: 'An adverb ("joyfully") is needed to modify the verb "played."' },
  { id: 'sat_rw_b6_017', category: 'reading', subcategory: 'vocabulary', difficulty: 'easy', passage: 'The scientist\'s findings were ________, supported by extensive data and repeated experiments.', question: 'Which word best completes the text?', options: [{ letter: 'A', text: 'reliable' }, { letter: 'B', text: 'questionable' }, { letter: 'C', text: 'dubious' }, { letter: 'D', text: 'flawed' }], correct: 'A', explanation: '"Reliable" means trustworthy, fitting findings backed by strong evidence.' },
  { id: 'sat_rw_b6_018', category: 'writing', subcategory: 'punctuation', difficulty: 'easy', passage: 'My brother________ who lives in Seattle________ is visiting us next week.', question: 'If the speaker has only one brother, which punctuation is needed?', options: [{ letter: 'A', text: ', ... ,' }, { letter: 'B', text: 'No punctuation needed' }, { letter: 'C', text: '; ... ;' }, { letter: 'D', text: '— ... —' }], correct: 'A', explanation: 'With only one brother, "who lives in Seattle" is nonessential and needs commas.' },
  { id: 'sat_rw_b6_019', category: 'reading', subcategory: 'vocabulary', difficulty: 'easy', passage: 'The author\'s writing style is ________; she uses simple words and short sentences to convey her ideas.', question: 'Which word best completes the text?', options: [{ letter: 'A', text: 'straightforward' }, { letter: 'B', text: 'elaborate' }, { letter: 'C', text: 'ornate' }, { letter: 'D', text: 'verbose' }], correct: 'A', explanation: '"Straightforward" means direct and uncomplicated, matching simple words and short sentences.' },
  { id: 'sat_rw_b6_020', category: 'writing', subcategory: 'grammar', difficulty: 'easy', passage: 'The students handed in ________ assignments before the deadline.', question: 'Which choice conforms to Standard English?', options: [{ letter: 'A', text: 'their' }, { letter: 'B', text: "they're" }, { letter: 'C', text: 'there' }, { letter: 'D', text: "there's" }], correct: 'A', explanation: '"Their" is the possessive pronoun referring to the students.' },
  { id: 'sat_rw_b6_021', category: 'writing', subcategory: 'sentence-structure', difficulty: 'easy', passage: 'The restaurant was crowded. We decided to eat at home instead.', question: 'Which choice best combines these sentences?', options: [{ letter: 'A', text: 'Because the restaurant was crowded, we decided to eat at home instead.' }, { letter: 'B', text: 'The restaurant was crowded, we decided to eat at home.' }, { letter: 'C', text: 'Crowded, the restaurant made us eat at home.' }, { letter: 'D', text: 'The restaurant was crowded and home was where we ate.' }], correct: 'A', explanation: '"Because" establishes the causal relationship between the crowded restaurant and the decision.' },
  { id: 'sat_rw_b6_022', category: 'reading', subcategory: 'reading-comprehension', difficulty: 'easy', passage: 'Recycling programs have expanded significantly in the past two decades. Many cities now offer curbside pickup for paper, plastic, and glass. Despite these efforts, contamination of recyclable materials remains a persistent challenge.', question: 'According to the passage, what is a continuing problem with recycling?', options: [{ letter: 'A', text: 'Contamination of recyclable materials' }, { letter: 'B', text: 'Lack of curbside pickup programs' }, { letter: 'C', text: 'Declining participation in recycling' }, { letter: 'D', text: 'Rising costs of recycling facilities' }], correct: 'A', explanation: 'The passage states that contamination remains a "persistent challenge."' },
  { id: 'sat_rw_b6_023', category: 'writing', subcategory: 'grammar', difficulty: 'easy', passage: 'The pie tasted ________ after it cooled on the windowsill.', question: 'Which choice conforms to Standard English?', options: [{ letter: 'A', text: 'delicious' }, { letter: 'B', text: 'deliciously' }, { letter: 'C', text: 'more deliciously' }, { letter: 'D', text: 'deliciousness' }], correct: 'A', explanation: '"Delicious" is an adjective following the linking verb "tasted" to describe the pie.' },
  { id: 'sat_rw_b6_024', category: 'reading', subcategory: 'vocabulary', difficulty: 'easy', passage: 'The politician made a ________ promise to lower taxes, but many voters doubted she could deliver on it.', question: 'Which word best completes the text?', options: [{ letter: 'A', text: 'bold' }, { letter: 'B', text: 'timid' }, { letter: 'C', text: 'vague' }, { letter: 'D', text: 'modest' }], correct: 'A', explanation: '"Bold" means daring and confident, fitting a significant promise that some find hard to believe.' },
  { id: 'sat_rw_b6_025', category: 'writing', subcategory: 'grammar', difficulty: 'easy', passage: 'Neither the manager nor the employees ________ aware of the policy change.', question: 'Which choice conforms to Standard English?', options: [{ letter: 'A', text: 'were' }, { letter: 'B', text: 'was' }, { letter: 'C', text: 'is' }, { letter: 'D', text: 'has been' }], correct: 'A', explanation: 'With "neither...nor," the verb agrees with the nearer subject "employees" (plural), requiring "were."' },
  { id: 'sat_rw_b6_026', category: 'writing', subcategory: 'punctuation', difficulty: 'easy', passage: 'The company\'s founder________ a retired engineer________ returned to advise the new CEO.', question: 'Which punctuation correctly sets off the appositive?', options: [{ letter: 'A', text: ', ... ,' }, { letter: 'B', text: '; ... ;' }, { letter: 'C', text: ': ... :' }, { letter: 'D', text: '( ... )' }], correct: 'A', explanation: 'Commas set off a nonessential appositive phrase identifying the founder.' },
  { id: 'sat_rw_b6_027', category: 'reading', subcategory: 'vocabulary', difficulty: 'easy', passage: 'The charity event was a ________ success, raising twice the amount of money organizers had expected.', question: 'Which word best completes the text?', options: [{ letter: 'A', text: 'remarkable' }, { letter: 'B', text: 'modest' }, { letter: 'C', text: 'marginal' }, { letter: 'D', text: 'negligible' }], correct: 'A', explanation: '"Remarkable" means worthy of attention, fitting an event that doubled its fundraising goal.' },
  { id: 'sat_rw_b6_028', category: 'writing', subcategory: 'grammar', difficulty: 'easy', passage: 'The team has ________ its goal of raising ten thousand dollars.', question: 'Which choice conforms to Standard English?', options: [{ letter: 'A', text: 'achieved' }, { letter: 'B', text: 'achieve' }, { letter: 'C', text: 'achieving' }, { letter: 'D', text: 'achieves' }], correct: 'A', explanation: '"Has achieved" is the present perfect tense, correct after "has."' },
  { id: 'sat_rw_b6_029', category: 'reading', subcategory: 'reading-comprehension', difficulty: 'easy', passage: 'The invention of the printing press in the fifteenth century transformed the spread of knowledge. Books, once painstakingly copied by hand, could now be produced quickly and cheaply. This made literature and scientific works accessible to a much wider audience.', question: 'What was the primary effect of the printing press described in the passage?', options: [{ letter: 'A', text: 'It made books available to more people' }, { letter: 'B', text: 'It replaced handwritten letters entirely' }, { letter: 'C', text: 'It decreased the quality of published works' }, { letter: 'D', text: 'It made books more expensive to produce' }], correct: 'A', explanation: 'The passage states books became "accessible to a much wider audience."' },
  { id: 'sat_rw_b6_030', category: 'writing', subcategory: 'sentence-structure', difficulty: 'easy', passage: 'The weather was warm. We went to the beach. We had a great time.', question: 'Which choice best combines these sentences?', options: [{ letter: 'A', text: 'Because the weather was warm, we went to the beach and had a great time.' }, { letter: 'B', text: 'The weather was warm, we went to the beach, we had a great time.' }, { letter: 'C', text: 'Warm weather and the beach and a great time.' }, { letter: 'D', text: 'The weather was warm and so we went to the beach and so we had a great time.' }], correct: 'A', explanation: 'Option A establishes cause and effect concisely without run-on structure.' },
  { id: 'sat_rw_b6_031', category: 'reading', subcategory: 'vocabulary', difficulty: 'easy', passage: 'The documentary presented a ________ account of the events, relying on interviews with eyewitnesses and official records.', question: 'Which word best completes the text?', options: [{ letter: 'A', text: 'factual' }, { letter: 'B', text: 'fictional' }, { letter: 'C', text: 'biased' }, { letter: 'D', text: 'speculative' }], correct: 'A', explanation: '"Factual" means based on facts, consistent with eyewitness accounts and official records.' },
  { id: 'sat_rw_b6_032', category: 'writing', subcategory: 'grammar', difficulty: 'easy', passage: 'The jury reached ________ verdict after two days of deliberation.', question: 'Which choice conforms to Standard English?', options: [{ letter: 'A', text: 'its' }, { letter: 'B', text: "it's" }, { letter: 'C', text: 'their' }, { letter: 'D', text: "they're" }], correct: 'A', explanation: '"Jury" is a singular collective noun, so the possessive pronoun is "its."' },
  { id: 'sat_rw_b6_033', category: 'reading', subcategory: 'vocabulary', difficulty: 'easy', passage: 'The negotiations between the two countries were ________, lasting several months before an agreement was reached.', question: 'Which word best completes the text?', options: [{ letter: 'A', text: 'prolonged' }, { letter: 'B', text: 'brief' }, { letter: 'C', text: 'effortless' }, { letter: 'D', text: 'hasty' }], correct: 'A', explanation: '"Prolonged" means extended over a long period, matching negotiations that lasted several months.' },
  { id: 'sat_rw_b6_034', category: 'writing', subcategory: 'punctuation', difficulty: 'easy', passage: 'The coach had one rule for the team________ always give maximum effort.', question: 'Which punctuation completes the text correctly?', options: [{ letter: 'A', text: ':' }, { letter: 'B', text: ',' }, { letter: 'C', text: ';' }, { letter: 'D', text: '.' }], correct: 'A', explanation: 'A colon introduces the specific rule after a complete introductory sentence.' },
  { id: 'sat_rw_b6_035', category: 'writing', subcategory: 'grammar', difficulty: 'easy', passage: 'Between the two proposals, the first one is ________.', question: 'Which choice conforms to Standard English?', options: [{ letter: 'A', text: 'better' }, { letter: 'B', text: 'best' }, { letter: 'C', text: 'more better' }, { letter: 'D', text: 'most good' }], correct: 'A', explanation: '"Better" is the comparative form used when comparing exactly two items.' },
  { id: 'sat_rw_b6_036', category: 'reading', subcategory: 'reading-comprehension', difficulty: 'easy', passage: 'Scientists have discovered that certain plants release chemicals into the soil that prevent other plants from growing nearby. This process, called allelopathy, gives the chemical-releasing plants a competitive advantage for sunlight, water, and nutrients.', question: 'Why do some plants use allelopathy?', options: [{ letter: 'A', text: 'To reduce competition for resources' }, { letter: 'B', text: 'To attract pollinating insects' }, { letter: 'C', text: 'To improve soil fertility' }, { letter: 'D', text: 'To protect themselves from herbivores' }], correct: 'A', explanation: 'The passage states allelopathy gives plants "a competitive advantage for sunlight, water, and nutrients."' },
  { id: 'sat_rw_b6_037', category: 'writing', subcategory: 'sentence-structure', difficulty: 'easy', passage: 'The book was long. It was interesting. I finished it in two days.', question: 'Which choice best combines these sentences?', options: [{ letter: 'A', text: 'Although the book was long, it was so interesting that I finished it in two days.' }, { letter: 'B', text: 'The book was long and interesting, finishing in two days.' }, { letter: 'C', text: 'Long and interesting, the book was finished in two days.' }, { letter: 'D', text: 'The book was long, it was interesting, I finished it in two days.' }], correct: 'A', explanation: '"Although" sets up the contrast between length and interest, and "so...that" shows cause and effect.' },
  { id: 'sat_rw_b6_038', category: 'reading', subcategory: 'vocabulary', difficulty: 'easy', passage: 'The company offered a ________ salary package to attract top talent from competing firms.', question: 'Which word best completes the text?', options: [{ letter: 'A', text: 'generous' }, { letter: 'B', text: 'meager' }, { letter: 'C', text: 'modest' }, { letter: 'D', text: 'inadequate' }], correct: 'A', explanation: '"Generous" means more than adequate, fitting a salary designed to attract top talent.' },
  { id: 'sat_rw_b6_039', category: 'writing', subcategory: 'grammar', difficulty: 'easy', passage: 'The news about the merger ________ everyone in the office by surprise.', question: 'Which choice conforms to Standard English?', options: [{ letter: 'A', text: 'took' }, { letter: 'B', text: 'take' }, { letter: 'C', text: 'takes' }, { letter: 'D', text: 'taking' }], correct: 'A', explanation: '"News" is singular. Past tense "took" is correct: "The news took everyone by surprise."' },
  { id: 'sat_rw_b6_040', category: 'reading', subcategory: 'vocabulary', difficulty: 'easy', passage: 'The old building was in a state of ________; its roof leaked, walls crumbled, and windows were shattered.', question: 'Which word best completes the text?', options: [{ letter: 'A', text: 'disrepair' }, { letter: 'B', text: 'renovation' }, { letter: 'C', text: 'splendor' }, { letter: 'D', text: 'preservation' }], correct: 'A', explanation: '"Disrepair" means poor condition due to neglect, matching the described damage.' },
  { id: 'sat_rw_b6_041', category: 'reading', subcategory: 'vocabulary', difficulty: 'medium', passage: 'The politician\'s speech was deliberately ________; by avoiding specific policy details, she appealed to a broad range of voters without alienating any particular group.', question: 'Which word best completes the text?', options: [{ letter: 'A', text: 'vague' }, { letter: 'B', text: 'precise' }, { letter: 'C', text: 'inflammatory' }, { letter: 'D', text: 'detailed' }], correct: 'A', explanation: '"Vague" means lacking specificity, matching the strategy of avoiding details to appeal broadly.' },
  { id: 'sat_rw_b6_042', category: 'writing', subcategory: 'grammar', difficulty: 'medium', passage: 'The orchestra, along with its conductor, ________ performing at the annual gala this Saturday.', question: 'Which choice conforms to Standard English?', options: [{ letter: 'A', text: 'is' }, { letter: 'B', text: 'are' }, { letter: 'C', text: 'were' }, { letter: 'D', text: 'have been' }], correct: 'A', explanation: '"Along with" is parenthetical; the subject is "orchestra" (singular), requiring "is."' },
  { id: 'sat_rw_b6_043', category: 'reading', subcategory: 'vocabulary', difficulty: 'medium', passage: 'The researcher\'s hypothesis was ________ by the experimental data; every test produced results consistent with her predictions.', question: 'Which word best completes the text?', options: [{ letter: 'A', text: 'corroborated' }, { letter: 'B', text: 'undermined' }, { letter: 'C', text: 'contradicted' }, { letter: 'D', text: 'dismissed' }], correct: 'A', explanation: '"Corroborated" means confirmed or supported, matching data consistent with predictions.' },
  { id: 'sat_rw_b6_044', category: 'writing', subcategory: 'punctuation', difficulty: 'medium', passage: 'The museum houses artifacts from several civilizations________ Egyptian, Greek, Roman, and Mesopotamian.', question: 'Which punctuation completes the text correctly?', options: [{ letter: 'A', text: ':' }, { letter: 'B', text: ',' }, { letter: 'C', text: ';' }, { letter: 'D', text: '—' }], correct: 'A', explanation: 'A colon introduces a list that specifies the civilizations mentioned.' },
  { id: 'sat_rw_b6_045', category: 'reading', subcategory: 'vocabulary', difficulty: 'medium', passage: 'The novelist\'s latest work is a ________ departure from her earlier romantic fiction; this new book is a gritty crime thriller set in a dystopian future.', question: 'Which word best completes the text?', options: [{ letter: 'A', text: 'stark' }, { letter: 'B', text: 'subtle' }, { letter: 'C', text: 'gradual' }, { letter: 'D', text: 'minor' }], correct: 'A', explanation: '"Stark" means sharply clear or complete, fitting a dramatic shift from romance to dystopian crime fiction.' },
  { id: 'sat_rw_b6_046', category: 'writing', subcategory: 'grammar', difficulty: 'medium', passage: 'If the committee ________ to approve the funding, the project will proceed as planned.', question: 'Which choice conforms to Standard English?', options: [{ letter: 'A', text: 'votes' }, { letter: 'B', text: 'vote' }, { letter: 'C', text: 'voting' }, { letter: 'D', text: 'voted' }], correct: 'A', explanation: '"Committee" is singular. In a conditional about a future event: "If the committee votes...will proceed."' },
  { id: 'sat_rw_b6_047', category: 'reading', subcategory: 'reading-comprehension', difficulty: 'medium', passage: 'The deep ocean remains one of the least explored regions on Earth. Despite covering more than sixty percent of the planet\'s surface, the deep sea has been mapped in less detail than the surface of Mars. Scientists estimate that thousands of species living in these depths have yet to be discovered.', question: 'What can be inferred from the passage?', options: [{ letter: 'A', text: 'Our knowledge of deep-sea biodiversity is far from complete' }, { letter: 'B', text: 'Deep-sea exploration is no longer a scientific priority' }, { letter: 'C', text: 'The surface of Mars is less explored than the ocean floor' }, { letter: 'D', text: 'Most deep-sea species have already been cataloged' }], correct: 'A', explanation: 'The passage states thousands of species "have yet to be discovered," implying incomplete knowledge.' },
  { id: 'sat_rw_b6_048', category: 'writing', subcategory: 'sentence-structure', difficulty: 'medium', passage: 'The study found that sleep deprivation impairs cognitive function. ________, it increases the risk of cardiovascular disease.', question: 'Which transition best connects these sentences?', options: [{ letter: 'A', text: 'Moreover' }, { letter: 'B', text: 'However' }, { letter: 'C', text: 'In contrast' }, { letter: 'D', text: 'Nevertheless' }], correct: 'A', explanation: '"Moreover" adds another negative effect of sleep deprivation, building on the first.' },
  { id: 'sat_rw_b6_049', category: 'reading', subcategory: 'vocabulary', difficulty: 'medium', passage: 'The diplomat was known for her ________ approach to negotiations; rather than making demands, she listened carefully and sought solutions acceptable to all parties.', question: 'Which word best completes the text?', options: [{ letter: 'A', text: 'conciliatory' }, { letter: 'B', text: 'combative' }, { letter: 'C', text: 'aggressive' }, { letter: 'D', text: 'domineering' }], correct: 'A', explanation: '"Conciliatory" means intended to placate or reconcile, matching a listening and solution-seeking approach.' },
  { id: 'sat_rw_b6_050', category: 'writing', subcategory: 'grammar', difficulty: 'medium', passage: 'Each of the participants ________ given a certificate upon completing the workshop.', question: 'Which choice conforms to Standard English?', options: [{ letter: 'A', text: 'was' }, { letter: 'B', text: 'were' }, { letter: 'C', text: 'are' }, { letter: 'D', text: 'have been' }], correct: 'A', explanation: '"Each" is singular, requiring "was."' },
  { id: 'sat_rw_b6_051', category: 'reading', subcategory: 'vocabulary', difficulty: 'medium', passage: 'The artist\'s early works were largely ________, drawing heavily on the styles and techniques of the Impressionists rather than developing an original voice.', question: 'Which word best completes the text?', options: [{ letter: 'A', text: 'derivative' }, { letter: 'B', text: 'innovative' }, { letter: 'C', text: 'groundbreaking' }, { letter: 'D', text: 'pioneering' }], correct: 'A', explanation: '"Derivative" means imitative of another\'s work, matching the description of borrowing from Impressionists.' },
  { id: 'sat_rw_b6_052', category: 'writing', subcategory: 'punctuation', difficulty: 'medium', passage: 'The city council approved the new park________ however, funding for the project has not yet been secured.', question: 'Which punctuation completes the text correctly?', options: [{ letter: 'A', text: ';' }, { letter: 'B', text: ',' }, { letter: 'C', text: ':' }, { letter: 'D', text: '—' }], correct: 'A', explanation: 'A semicolon joins two independent clauses when the second begins with a conjunctive adverb like "however."' },
  { id: 'sat_rw_b6_053', category: 'writing', subcategory: 'grammar', difficulty: 'medium', passage: 'The data from the latest survey ________ that consumer spending has increased significantly.', question: 'Which choice conforms to Standard English?', options: [{ letter: 'A', text: 'suggests' }, { letter: 'B', text: 'suggest' }, { letter: 'C', text: 'suggesting' }, { letter: 'D', text: 'have suggested' }], correct: 'A', explanation: '"Data" can be treated as singular in modern English; "suggests" agrees with the singular sense.' },
  { id: 'sat_rw_b6_054', category: 'reading', subcategory: 'reading-comprehension', difficulty: 'medium', passage: 'Coral reefs support approximately twenty-five percent of all marine species despite covering less than one percent of the ocean floor. Rising ocean temperatures have caused widespread coral bleaching, a phenomenon in which stressed corals expel the symbiotic algae that provide them with nutrients and color. Without intervention, scientists predict that up to ninety percent of coral reefs could be lost by 2050.', question: 'What is the relationship between coral bleaching and the algae described in the passage?', options: [{ letter: 'A', text: 'Bleaching occurs when corals lose the algae that sustain them' }, { letter: 'B', text: 'Bleaching causes algae to multiply within the coral' }, { letter: 'C', text: 'Algae are responsible for causing coral bleaching' }, { letter: 'D', text: 'Bleaching strengthens the bond between coral and algae' }], correct: 'A', explanation: 'The passage states corals "expel the symbiotic algae" during bleaching.' },
  { id: 'sat_rw_b6_055', category: 'writing', subcategory: 'sentence-structure', difficulty: 'medium', passage: 'Renewable energy sources are becoming more affordable. ________, many countries continue to rely heavily on fossil fuels.', question: 'Which transition best connects these sentences?', options: [{ letter: 'A', text: 'Nevertheless' }, { letter: 'B', text: 'Therefore' }, { letter: 'C', text: 'Similarly' }, { letter: 'D', text: 'Consequently' }], correct: 'A', explanation: '"Nevertheless" signals a contrast: despite affordability, fossil fuels still dominate.' },
  { id: 'sat_rw_b6_056', category: 'reading', subcategory: 'vocabulary', difficulty: 'medium', passage: 'The CEO\'s decision to expand into foreign markets was considered ________ by industry analysts, who noted that no other company in the sector had attempted such a move.', question: 'Which word best completes the text?', options: [{ letter: 'A', text: 'audacious' }, { letter: 'B', text: 'cautious' }, { letter: 'C', text: 'conventional' }, { letter: 'D', text: 'predictable' }], correct: 'A', explanation: '"Audacious" means showing a willingness to take bold risks, fitting an unprecedented move.' },
  { id: 'sat_rw_b6_057', category: 'writing', subcategory: 'grammar', difficulty: 'medium', passage: 'It is crucial that every team member ________ the safety protocol before entering the laboratory.', question: 'Which choice conforms to Standard English?', options: [{ letter: 'A', text: 'review' }, { letter: 'B', text: 'reviews' }, { letter: 'C', text: 'reviewed' }, { letter: 'D', text: 'will review' }], correct: 'A', explanation: 'The subjunctive mood after "crucial that" uses the base form: "review."' },
  { id: 'sat_rw_b6_058', category: 'writing', subcategory: 'punctuation', difficulty: 'medium', passage: 'The conference featured speakers from three universities________ Stanford, where the keynote was delivered; MIT, which hosted a panel on robotics; and Harvard, which organized a session on public policy.', question: 'Which punctuation completes the text correctly?', options: [{ letter: 'A', text: ':' }, { letter: 'B', text: ',' }, { letter: 'C', text: ';' }, { letter: 'D', text: '—' }], correct: 'A', explanation: 'A colon introduces the list, and semicolons separate items containing internal commas.' },
  { id: 'sat_rw_b6_059', category: 'reading', subcategory: 'vocabulary', difficulty: 'medium', passage: 'While some critics dismissed the novel as overly sentimental, others praised its ________ portrayal of grief, arguing that it captured the complexity of loss without resorting to cliches.', question: 'Which word best completes the text?', options: [{ letter: 'A', text: 'nuanced' }, { letter: 'B', text: 'superficial' }, { letter: 'C', text: 'simplistic' }, { letter: 'D', text: 'exaggerated' }], correct: 'A', explanation: '"Nuanced" means showing subtle differences and complexity, matching the description of capturing loss\'s complexity.' },
  { id: 'sat_rw_b6_060', category: 'writing', subcategory: 'grammar', difficulty: 'medium', passage: 'The number of students enrolling in online courses ________ risen sharply in recent years.', question: 'Which choice conforms to Standard English?', options: [{ letter: 'A', text: 'has' }, { letter: 'B', text: 'have' }, { letter: 'C', text: 'are' }, { letter: 'D', text: 'were' }], correct: 'A', explanation: '"The number" is singular, requiring "has."' },
  { id: 'sat_rw_b6_061', category: 'reading', subcategory: 'reading-comprehension', difficulty: 'medium', passage: 'The placebo effect occurs when patients experience improvement in their condition after receiving an inactive treatment. Researchers have found that the strength of the placebo effect varies depending on factors such as the patient\'s expectations, the perceived credibility of the treatment, and even the color of the pill administered.', question: 'According to the passage, which factor influences the strength of the placebo effect?', options: [{ letter: 'A', text: 'The patient\'s expectations about the treatment' }, { letter: 'B', text: 'The chemical composition of the placebo' }, { letter: 'C', text: 'The severity of the patient\'s illness' }, { letter: 'D', text: 'The number of doses administered' }], correct: 'A', explanation: 'The passage lists "the patient\'s expectations" as one factor affecting the placebo effect.' },
  { id: 'sat_rw_b6_062', category: 'writing', subcategory: 'sentence-structure', difficulty: 'medium', passage: 'The company reduced its carbon emissions by thirty percent last year. ________, it invested in reforestation projects to offset remaining emissions.', question: 'Which transition best connects these sentences?', options: [{ letter: 'A', text: 'Additionally' }, { letter: 'B', text: 'However' }, { letter: 'C', text: 'In contrast' }, { letter: 'D', text: 'Conversely' }], correct: 'A', explanation: '"Additionally" introduces a second action the company took alongside the first.' },
  { id: 'sat_rw_b6_063', category: 'reading', subcategory: 'vocabulary', difficulty: 'medium', passage: 'The archaeologist described the discovery as ________; the well-preserved artifacts offered an unprecedented window into daily life during the Bronze Age.', question: 'Which word best completes the text?', options: [{ letter: 'A', text: 'momentous' }, { letter: 'B', text: 'trivial' }, { letter: 'C', text: 'routine' }, { letter: 'D', text: 'insignificant' }], correct: 'A', explanation: '"Momentous" means of great importance, fitting a discovery described as unprecedented.' },
  { id: 'sat_rw_b6_064', category: 'writing', subcategory: 'grammar', difficulty: 'medium', passage: 'She is one of those managers who ________ always open to feedback from their team.', question: 'Which choice conforms to Standard English?', options: [{ letter: 'A', text: 'are' }, { letter: 'B', text: 'is' }, { letter: 'C', text: 'was' }, { letter: 'D', text: 'has been' }], correct: 'A', explanation: '"Who" refers to "managers" (plural), so "are" is correct: "managers who are always open."' },
  { id: 'sat_rw_b6_065', category: 'writing', subcategory: 'punctuation', difficulty: 'medium', passage: 'The researcher emphasized one finding above all________ sleep quality matters more than sleep duration.', question: 'Which punctuation completes the text correctly?', options: [{ letter: 'A', text: ':' }, { letter: 'B', text: ',' }, { letter: 'C', text: ';' }, { letter: 'D', text: '.' }], correct: 'A', explanation: 'A colon introduces the specific finding that elaborates on the general statement.' },
  { id: 'sat_rw_b6_066', category: 'reading', subcategory: 'vocabulary', difficulty: 'medium', passage: 'The professor\'s lectures were ________; students often struggled to follow her rapid transitions between complex theories and abstract concepts.', question: 'Which word best completes the text?', options: [{ letter: 'A', text: 'dense' }, { letter: 'B', text: 'accessible' }, { letter: 'C', text: 'elementary' }, { letter: 'D', text: 'superficial' }], correct: 'A', explanation: '"Dense" means packed with complex information, matching lectures that students struggled to follow.' },
  { id: 'sat_rw_b6_067', category: 'writing', subcategory: 'grammar', difficulty: 'medium', passage: 'The museum\'s collection includes sculptures by artists ________ work has been exhibited internationally.', question: 'Which choice conforms to Standard English?', options: [{ letter: 'A', text: 'whose' }, { letter: 'B', text: "who's" }, { letter: 'C', text: 'which' }, { letter: 'D', text: 'whom' }], correct: 'A', explanation: '"Whose" shows possession; the work belongs to the artists.' },
  { id: 'sat_rw_b6_068', category: 'reading', subcategory: 'reading-comprehension', difficulty: 'medium', passage: 'Urban heat islands form when cities replace natural vegetation with dense concentrations of pavement and buildings that absorb and retain heat. As a result, urban areas can be several degrees warmer than surrounding rural regions. Researchers have found that planting trees and installing green roofs can significantly reduce this temperature difference.', question: 'Based on the passage, what causes urban heat islands?', options: [{ letter: 'A', text: 'Replacement of vegetation with heat-absorbing surfaces' }, { letter: 'B', text: 'Increased use of air conditioning in cities' }, { letter: 'C', text: 'Higher population density in urban areas' }, { letter: 'D', text: 'Industrial pollution from factories' }], correct: 'A', explanation: 'The passage directly states that replacing vegetation with pavement and buildings causes heat islands.' },
  { id: 'sat_rw_b6_069', category: 'writing', subcategory: 'sentence-structure', difficulty: 'medium', passage: 'The experiment yielded unexpected results. The researchers decided to repeat it with a larger sample size. They also refined their methodology.', question: 'Which choice best combines the second and third sentences?', options: [{ letter: 'A', text: 'The researchers decided to repeat the experiment with a larger sample size and a refined methodology.' }, { letter: 'B', text: 'The researchers decided to repeat it, they also refined their methodology.' }, { letter: 'C', text: 'Repeating the experiment with more samples and refining methodology was decided.' }, { letter: 'D', text: 'The researchers decided to repeat it and they also decided to refine their methodology too.' }], correct: 'A', explanation: 'Option A concisely combines both actions using parallel structure with "and."' },
  { id: 'sat_rw_b6_070', category: 'reading', subcategory: 'vocabulary', difficulty: 'medium', passage: 'The CEO\'s ________ leadership style fostered creativity among employees, who felt free to propose unconventional ideas without fear of criticism.', question: 'Which word best completes the text?', options: [{ letter: 'A', text: 'permissive' }, { letter: 'B', text: 'authoritarian' }, { letter: 'C', text: 'rigid' }, { letter: 'D', text: 'dictatorial' }], correct: 'A', explanation: '"Permissive" means allowing great freedom, matching an environment where employees feel free to share ideas.' },
  { id: 'sat_rw_b6_071', category: 'writing', subcategory: 'grammar', difficulty: 'medium', passage: 'Not only ________ the new software improve efficiency, but it also reduced errors by forty percent.', question: 'Which choice conforms to Standard English?', options: [{ letter: 'A', text: 'did' }, { letter: 'B', text: 'does' }, { letter: 'C', text: 'was' }, { letter: 'D', text: 'had' }], correct: 'A', explanation: '"Not only did...but also" is the correct inverted structure for past tense.' },
  { id: 'sat_rw_b6_072', category: 'writing', subcategory: 'punctuation', difficulty: 'medium', passage: 'The panel included experts from diverse fields________ Dr. Patel, a geneticist; Ms. Rivera, an economist; and Mr. Cho, a civil engineer.', question: 'Which punctuation completes the text correctly?', options: [{ letter: 'A', text: ':' }, { letter: 'B', text: ',' }, { letter: 'C', text: ';' }, { letter: 'D', text: '—' }], correct: 'A', explanation: 'A colon introduces the list, and semicolons separate items with internal commas.' },
  { id: 'sat_rw_b6_073', category: 'reading', subcategory: 'vocabulary', difficulty: 'medium', passage: 'The witness\'s account of the accident was ________; she provided precise details about the sequence of events, the vehicles involved, and the weather conditions.', question: 'Which word best completes the text?', options: [{ letter: 'A', text: 'thorough' }, { letter: 'B', text: 'cursory' }, { letter: 'C', text: 'incomplete' }, { letter: 'D', text: 'superficial' }], correct: 'A', explanation: '"Thorough" means complete and detailed, matching the precise and comprehensive account described.' },
  { id: 'sat_rw_b6_074', category: 'writing', subcategory: 'grammar', difficulty: 'medium', passage: 'The CEO and the board chair ________ scheduled to address the shareholders at tomorrow\'s meeting.', question: 'Which choice conforms to Standard English?', options: [{ letter: 'A', text: 'are' }, { letter: 'B', text: 'is' }, { letter: 'C', text: 'was' }, { letter: 'D', text: 'has been' }], correct: 'A', explanation: '"The CEO and the board chair" are two different people, forming a plural compound subject requiring "are."' },
  { id: 'sat_rw_b6_075', category: 'reading', subcategory: 'reading-comprehension', difficulty: 'medium', passage: 'Migration patterns of monarch butterflies have puzzled scientists for decades. Each autumn, millions of monarchs travel up to three thousand miles from Canada to central Mexico. Remarkably, no single butterfly completes the entire round trip; it takes multiple generations to complete the full migratory cycle.', question: 'What is remarkable about the monarch butterfly\'s migration?', options: [{ letter: 'A', text: 'The round trip requires multiple generations to complete' }, { letter: 'B', text: 'Each butterfly travels the entire route alone' }, { letter: 'C', text: 'The butterflies migrate only a few hundred miles' }, { letter: 'D', text: 'Scientists fully understand how monarchs navigate' }], correct: 'A', explanation: 'The passage states it "takes multiple generations to complete the full migratory cycle."' },
  { id: 'sat_rw_b6_076', category: 'writing', subcategory: 'sentence-structure', difficulty: 'medium', passage: 'The ancient city was a center of trade. ________, it was a hub for cultural exchange and artistic innovation.', question: 'Which transition best connects these sentences?', options: [{ letter: 'A', text: 'Furthermore' }, { letter: 'B', text: 'However' }, { letter: 'C', text: 'In contrast' }, { letter: 'D', text: 'On the other hand' }], correct: 'A', explanation: '"Furthermore" adds another role the city played, building on the first statement.' },
  { id: 'sat_rw_b6_077', category: 'reading', subcategory: 'vocabulary', difficulty: 'medium', passage: 'The journalist\'s investigation revealed a ________ of corruption within the organization, exposing bribery, fraud, and embezzlement at every level.', question: 'Which word best completes the text?', options: [{ letter: 'A', text: 'pattern' }, { letter: 'B', text: 'lack' }, { letter: 'C', text: 'absence' }, { letter: 'D', text: 'scarcity' }], correct: 'A', explanation: '"Pattern" means a repeated occurrence, fitting corruption found at every level.' },
  { id: 'sat_rw_b6_078', category: 'writing', subcategory: 'grammar', difficulty: 'medium', passage: 'Barely ________ the presentation begun when the fire alarm interrupted it.', question: 'Which choice conforms to Standard English?', options: [{ letter: 'A', text: 'had' }, { letter: 'B', text: 'has' }, { letter: 'C', text: 'did' }, { letter: 'D', text: 'was' }], correct: 'A', explanation: '"Barely had...when" is the correct inverted past perfect structure.' },
  { id: 'sat_rw_b6_079', category: 'writing', subcategory: 'punctuation', difficulty: 'medium', passage: 'The results were conclusive________ patients who received the new treatment recovered twice as fast as those in the control group.', question: 'Which punctuation completes the text correctly?', options: [{ letter: 'A', text: ':' }, { letter: 'B', text: ',' }, { letter: 'C', text: ';' }, { letter: 'D', text: '—' }], correct: 'A', explanation: 'A colon introduces the specific evidence supporting the general claim.' },
  { id: 'sat_rw_b6_080', category: 'reading', subcategory: 'vocabulary', difficulty: 'medium', passage: 'The philosopher\'s argument was ________; each premise logically followed from the one before it, leading inevitably to her conclusion.', question: 'Which word best completes the text?', options: [{ letter: 'A', text: 'cogent' }, { letter: 'B', text: 'flawed' }, { letter: 'C', text: 'incoherent' }, { letter: 'D', text: 'specious' }], correct: 'A', explanation: '"Cogent" means clear, logical, and convincing, matching a well-structured argument.' },
  { id: 'sat_rw_b6_081', category: 'writing', subcategory: 'grammar', difficulty: 'medium', passage: 'The evidence collected at the scene ________ to a single suspect.', question: 'Which choice conforms to Standard English?', options: [{ letter: 'A', text: 'points' }, { letter: 'B', text: 'point' }, { letter: 'C', text: 'pointing' }, { letter: 'D', text: 'have pointed' }], correct: 'A', explanation: '"Evidence" is an uncountable singular noun requiring the singular verb "points."' },
  { id: 'sat_rw_b6_082', category: 'reading', subcategory: 'reading-comprehension', difficulty: 'medium', passage: 'Studies have shown that bilingual individuals often outperform monolinguals on tasks requiring attention and mental flexibility. Researchers attribute this advantage to the constant practice bilinguals get in switching between languages, which strengthens executive function in the brain.', question: 'According to the passage, why do bilingual individuals have a cognitive advantage?', options: [{ letter: 'A', text: 'Regularly switching between languages strengthens brain function' }, { letter: 'B', text: 'Learning two languages increases overall intelligence' }, { letter: 'C', text: 'Bilingual individuals have larger vocabularies' }, { letter: 'D', text: 'Speaking two languages improves memory capacity' }], correct: 'A', explanation: 'The passage attributes the advantage to "constant practice in switching between languages."' },
  { id: 'sat_rw_b6_083', category: 'writing', subcategory: 'sentence-structure', difficulty: 'medium', passage: 'The town invested in flood barriers. ________, it established an early warning system for residents in vulnerable areas.', question: 'Which transition best connects these sentences?', options: [{ letter: 'A', text: 'In addition' }, { letter: 'B', text: 'However' }, { letter: 'C', text: 'Instead' }, { letter: 'D', text: 'On the contrary' }], correct: 'A', explanation: '"In addition" introduces a second preparedness measure the town implemented.' },
  { id: 'sat_rw_b6_084', category: 'reading', subcategory: 'vocabulary', difficulty: 'medium', passage: 'The candidate\'s ________ response during the debate revealed her deep understanding of economic policy; she cited specific statistics and historical precedents with ease.', question: 'Which word best completes the text?', options: [{ letter: 'A', text: 'articulate' }, { letter: 'B', text: 'inarticulate' }, { letter: 'C', text: 'rambling' }, { letter: 'D', text: 'evasive' }], correct: 'A', explanation: '"Articulate" means expressing ideas clearly and fluently, matching the detailed and knowledgeable response.' },
  { id: 'sat_rw_b6_085', category: 'writing', subcategory: 'grammar', difficulty: 'medium', passage: 'The teacher asked ________ had completed the reading assignment before class.', question: 'Which choice conforms to Standard English?', options: [{ letter: 'A', text: 'who' }, { letter: 'B', text: 'whom' }, { letter: 'C', text: 'which' }, { letter: 'D', text: 'that' }], correct: 'A', explanation: '"Who" is the subject of "had completed." (Whom is the object form.)' },
  { id: 'sat_rw_b6_086', category: 'writing', subcategory: 'punctuation', difficulty: 'medium', passage: 'The play explores a timeless question________ what does it mean to live a meaningful life?', question: 'Which punctuation completes the text correctly?', options: [{ letter: 'A', text: ':' }, { letter: 'B', text: ',' }, { letter: 'C', text: ';' }, { letter: 'D', text: '.' }], correct: 'A', explanation: 'A colon introduces the specific question referenced in the main clause.' },
  { id: 'sat_rw_b6_087', category: 'reading', subcategory: 'vocabulary', difficulty: 'medium', passage: 'The historian argued that the treaty was ________; its terms were so harsh that they virtually guaranteed future conflict between the nations.', question: 'Which word best completes the text?', options: [{ letter: 'A', text: 'counterproductive' }, { letter: 'B', text: 'effective' }, { letter: 'C', text: 'fair' }, { letter: 'D', text: 'beneficial' }], correct: 'A', explanation: '"Counterproductive" means having the opposite of the desired effect, fitting a peace treaty that guaranteed future conflict.' },
  { id: 'sat_rw_b6_088', category: 'writing', subcategory: 'grammar', difficulty: 'medium', passage: 'The report, along with its appendices, ________ submitted to the review board last Friday.', question: 'Which choice conforms to Standard English?', options: [{ letter: 'A', text: 'was' }, { letter: 'B', text: 'were' }, { letter: 'C', text: 'are' }, { letter: 'D', text: 'have been' }], correct: 'A', explanation: '"Along with" is parenthetical; the subject is "report" (singular), requiring "was."' },
  { id: 'sat_rw_b6_089', category: 'reading', subcategory: 'reading-comprehension', difficulty: 'medium', passage: 'Microplastics have been found in virtually every environment on Earth, from the deepest ocean trenches to the peaks of remote mountains. These tiny particles, which result from the breakdown of larger plastic items, can enter the food chain when ingested by marine organisms. Studies suggest that humans may consume tens of thousands of microplastic particles each year through food and water.', question: 'What can be inferred from the passage about the spread of microplastics?', options: [{ letter: 'A', text: 'Microplastics have become virtually ubiquitous in the environment' }, { letter: 'B', text: 'Microplastics are found only in ocean environments' }, { letter: 'C', text: 'Humans are not affected by microplastic contamination' }, { letter: 'D', text: 'Microplastics are easily removed from the environment' }], correct: 'A', explanation: 'The passage states microplastics are found in "virtually every environment on Earth."' },
  { id: 'sat_rw_b6_090', category: 'writing', subcategory: 'sentence-structure', difficulty: 'medium', passage: 'The policy was designed to reduce poverty. ________, critics argued that it would discourage employment by providing benefits without work requirements.', question: 'Which transition best connects these sentences?', options: [{ letter: 'A', text: 'However' }, { letter: 'B', text: 'Therefore' }, { letter: 'C', text: 'Similarly' }, { letter: 'D', text: 'Consequently' }], correct: 'A', explanation: '"However" introduces a contrasting criticism of the policy\'s design.' },
  { id: 'sat_rw_b6_091', category: 'reading', subcategory: 'vocabulary', difficulty: 'hard', passage: 'The author\'s prose style is deliberately ________; her sentences unfold in long, winding clauses that mirror the protagonist\'s fragmented consciousness, demanding sustained attention from the reader.', question: 'Which word best completes the text?', options: [{ letter: 'A', text: 'labyrinthine' }, { letter: 'B', text: 'succinct' }, { letter: 'C', text: 'pedestrian' }, { letter: 'D', text: 'transparent' }], correct: 'A', explanation: '"Labyrinthine" means intricate and complex like a labyrinth, matching the long, winding prose described.' },
  { id: 'sat_rw_b6_092', category: 'writing', subcategory: 'grammar', difficulty: 'hard', passage: 'Had the researchers ________ the potential for contamination, the experiment\'s results might have been more reliable.', question: 'Which choice conforms to Standard English?', options: [{ letter: 'A', text: 'anticipated' }, { letter: 'B', text: 'anticipating' }, { letter: 'C', text: 'anticipate' }, { letter: 'D', text: 'anticipates' }], correct: 'A', explanation: 'Inverted conditional: "Had the researchers anticipated" = "If the researchers had anticipated."' },
  { id: 'sat_rw_b6_093', category: 'reading', subcategory: 'vocabulary', difficulty: 'hard', passage: 'The philosopher rejected the ________ view of human nature as fundamentally selfish, arguing instead that cooperation and mutual aid are deeply embedded in our evolutionary history.', question: 'Which word best completes the text?', options: [{ letter: 'A', text: 'cynical' }, { letter: 'B', text: 'optimistic' }, { letter: 'C', text: 'idealistic' }, { letter: 'D', text: 'romantic' }], correct: 'A', explanation: '"Cynical" means distrustful of human sincerity, fitting the view of humans as fundamentally selfish.' },
  { id: 'sat_rw_b6_094', category: 'writing', subcategory: 'punctuation', difficulty: 'hard', passage: 'The study identified three variables that significantly predicted academic success________ parental involvement, which correlated with higher grades; access to educational resources, which reduced achievement gaps; and quality of instruction, which improved standardized test scores.', question: 'Which punctuation completes the text correctly?', options: [{ letter: 'A', text: ':' }, { letter: 'B', text: ',' }, { letter: 'C', text: ';' }, { letter: 'D', text: '—' }], correct: 'A', explanation: 'A colon introduces the detailed list, with semicolons separating items that contain internal commas.' },
  { id: 'sat_rw_b6_095', category: 'reading', subcategory: 'vocabulary', difficulty: 'hard', passage: 'The diplomat\'s speech was a masterwork of ________; while appearing to concede key points, she actually reframed the debate in terms favorable to her country\'s position.', question: 'Which word best completes the text?', options: [{ letter: 'A', text: 'equivocation' }, { letter: 'B', text: 'candor' }, { letter: 'C', text: 'transparency' }, { letter: 'D', text: 'forthrightness' }], correct: 'A', explanation: '"Equivocation" means using ambiguous language to mislead, matching the diplomat\'s strategic reframing.' },
  { id: 'sat_rw_b6_096', category: 'writing', subcategory: 'grammar', difficulty: 'hard', passage: 'The professor, as well as her graduate assistants, ________ been invited to present at the international symposium.', question: 'Which choice conforms to Standard English?', options: [{ letter: 'A', text: 'has' }, { letter: 'B', text: 'have' }, { letter: 'C', text: 'are' }, { letter: 'D', text: 'were' }], correct: 'A', explanation: '"As well as" is parenthetical; the subject is "professor" (singular), requiring "has."' },
  { id: 'sat_rw_b6_097', category: 'reading', subcategory: 'reading-comprehension', difficulty: 'hard', passage: 'Critics of standardized testing argue that such assessments measure only a narrow range of cognitive skills and fail to account for creativity, emotional intelligence, or practical problem-solving ability. Proponents counter that standardized tests provide an objective benchmark for comparing students across different schools and districts. However, recent research suggests that socioeconomic factors may influence test performance as much as academic preparation does, raising questions about whether these tests truly measure aptitude.', question: 'The author mentions socioeconomic factors primarily to ________', options: [{ letter: 'A', text: 'complicate the claim that standardized tests are objective measures of ability' }, { letter: 'B', text: 'support the argument that standardized tests are reliable' }, { letter: 'C', text: 'dismiss the concerns of testing critics entirely' }, { letter: 'D', text: 'suggest that all students have equal access to test preparation' }], correct: 'A', explanation: 'The socioeconomic research raises questions about whether tests "truly measure aptitude," undermining the objectivity claim.' },
  { id: 'sat_rw_b6_098', category: 'writing', subcategory: 'sentence-structure', difficulty: 'hard', passage: 'The archaeological evidence supports the migration theory. However, linguistic analysis suggests a different origin for the population. DNA studies, meanwhile, present yet another possibility.', question: 'Which choice best combines the second and third sentences?', options: [{ letter: 'A', text: 'However, linguistic analysis suggests a different origin for the population, while DNA studies present yet another possibility.' }, { letter: 'B', text: 'However, linguistic analysis and DNA studies suggest different things about the population.' }, { letter: 'C', text: 'However, suggesting a different origin and presenting another possibility, linguistic and DNA studies disagree.' }, { letter: 'D', text: 'However, linguistic analysis suggests differently, and DNA studies presenting yet another possibility.' }], correct: 'A', explanation: '"While" effectively contrasts the two distinct alternative theories.' },
  { id: 'sat_rw_b6_099', category: 'reading', subcategory: 'vocabulary', difficulty: 'hard', passage: 'The biographer\'s account was criticized as excessively ________; by omitting the subject\'s personal failures and ethical lapses, the author presented an unrealistically positive portrait.', question: 'Which word best completes the text?', options: [{ letter: 'A', text: 'hagiographic' }, { letter: 'B', text: 'disparaging' }, { letter: 'C', text: 'balanced' }, { letter: 'D', text: 'critical' }], correct: 'A', explanation: '"Hagiographic" means idealizing or idolizing, fitting a biography that omits flaws to present an overly positive image.' },
  { id: 'sat_rw_b6_100', category: 'writing', subcategory: 'grammar', difficulty: 'hard', passage: 'It is imperative that the board ________ the revised budget before the end of the fiscal year.', question: 'Which choice conforms to Standard English?', options: [{ letter: 'A', text: 'approve' }, { letter: 'B', text: 'approves' }, { letter: 'C', text: 'approved' }, { letter: 'D', text: 'will approve' }], correct: 'A', explanation: 'The subjunctive mood after "imperative that" uses the base form: "approve."' },
  { id: 'sat_rw_b6_101', category: 'writing', subcategory: 'punctuation', difficulty: 'hard', passage: 'The architect\'s design was praised for its elegance________ a quality that, in the judges\' view, set it apart from the more functional but aesthetically uninspired submissions.', question: 'Which punctuation completes the text correctly?', options: [{ letter: 'A', text: '—' }, { letter: 'B', text: ',' }, { letter: 'C', text: ';' }, { letter: 'D', text: ':' }], correct: 'A', explanation: 'An em dash introduces an elaborating phrase that expands on the idea of elegance.' },
  { id: 'sat_rw_b6_102', category: 'reading', subcategory: 'vocabulary', difficulty: 'hard', passage: 'The economist described the government\'s approach to regulation as ________; by imposing strict rules without considering their unintended consequences, policymakers had inadvertently stifled the very innovation they sought to promote.', question: 'Which word best completes the text?', options: [{ letter: 'A', text: 'myopic' }, { letter: 'B', text: 'visionary' }, { letter: 'C', text: 'prudent' }, { letter: 'D', text: 'farsighted' }], correct: 'A', explanation: '"Myopic" means short-sighted, fitting a policy that failed to consider long-term consequences.' },
  { id: 'sat_rw_b6_103', category: 'writing', subcategory: 'grammar', difficulty: 'hard', passage: 'The attorney to ________ the case was assigned has requested a continuance.', question: 'Which choice conforms to Standard English?', options: [{ letter: 'A', text: 'whom' }, { letter: 'B', text: 'who' }, { letter: 'C', text: 'which' }, { letter: 'D', text: 'that' }], correct: 'A', explanation: '"Whom" is the object of the preposition "to": the case was assigned to whom.' },
  { id: 'sat_rw_b6_104', category: 'reading', subcategory: 'reading-comprehension', difficulty: 'hard', passage: 'The Sapir-Whorf hypothesis, in its strong form, proposes that the language we speak determines the way we think. However, most modern linguists favor a weaker version of the hypothesis, which holds that language influences but does not rigidly determine thought. Studies of color perception across cultures provide some support for the weaker claim, showing that speakers of languages with more color terms can distinguish subtle shades more quickly, though not that they are unable to perceive those shades at all.', question: 'The color perception studies are cited primarily to ________', options: [{ letter: 'A', text: 'provide evidence for the weaker version of the Sapir-Whorf hypothesis' }, { letter: 'B', text: 'prove that the strong version of the hypothesis is correct' }, { letter: 'C', text: 'demonstrate that language has no effect on perception' }, { letter: 'D', text: 'argue that all languages have the same number of color terms' }], correct: 'A', explanation: 'The studies show language influences speed of color distinction (supporting the weak form) but not ability (refuting the strong form).' },
  { id: 'sat_rw_b6_105', category: 'writing', subcategory: 'sentence-structure', difficulty: 'hard', passage: 'The painting appears simple at first glance. Closer examination reveals intricate layers of symbolism. Art historians have debated its meaning for decades.', question: 'Which choice best combines these sentences?', options: [{ letter: 'A', text: 'Although the painting appears simple at first glance, closer examination reveals intricate layers of symbolism that art historians have debated for decades.' }, { letter: 'B', text: 'The painting is simple but has symbolism that historians debate.' }, { letter: 'C', text: 'Appearing simple, the painting\'s symbolism has been debated, and closer examination reveals layers.' }, { letter: 'D', text: 'The painting appears simple at first glance, closer examination reveals symbolism, historians have debated it.' }], correct: 'A', explanation: '"Although" sets up the contrast, and "that" introduces the relative clause about the ongoing debate.' },
  { id: 'sat_rw_b6_106', category: 'reading', subcategory: 'vocabulary', difficulty: 'hard', passage: 'The sociologist observed that the community\'s response to the crisis was ________; rather than fracturing along existing lines of division, residents came together in an unprecedented display of solidarity.', question: 'Which word best completes the text?', options: [{ letter: 'A', text: 'galvanizing' }, { letter: 'B', text: 'divisive' }, { letter: 'C', text: 'polarizing' }, { letter: 'D', text: 'fragmenting' }], correct: 'A', explanation: '"Galvanizing" means shocking or exciting someone into action or unity, matching the description of residents uniting.' },
  { id: 'sat_rw_b6_107', category: 'writing', subcategory: 'grammar', difficulty: 'hard', passage: 'The diversity of ecosystems found across the archipelago ________ scientists who study biogeography.', question: 'Which choice conforms to Standard English?', options: [{ letter: 'A', text: 'fascinates' }, { letter: 'B', text: 'fascinate' }, { letter: 'C', text: 'fascinating' }, { letter: 'D', text: 'have fascinated' }], correct: 'A', explanation: '"Diversity" is a singular subject requiring the singular verb "fascinates."' },
  { id: 'sat_rw_b6_108', category: 'writing', subcategory: 'punctuation', difficulty: 'hard', passage: 'The CEO outlined the company\'s priorities for the coming year________ expanding into Asian markets, increasing investment in research and development, and reducing the environmental impact of manufacturing operations.', question: 'Which punctuation completes the text correctly?', options: [{ letter: 'A', text: ':' }, { letter: 'B', text: ',' }, { letter: 'C', text: ';' }, { letter: 'D', text: '—' }], correct: 'A', explanation: 'A colon introduces a list that specifies the priorities mentioned.' },
  { id: 'sat_rw_b6_109', category: 'reading', subcategory: 'vocabulary', difficulty: 'hard', passage: 'The literary critic argued that the novel\'s ending was deliberately ________; by refusing to resolve the central conflict, the author forced readers to grapple with the same uncertainty that plagued the characters.', question: 'Which word best completes the text?', options: [{ letter: 'A', text: 'ambiguous' }, { letter: 'B', text: 'definitive' }, { letter: 'C', text: 'predictable' }, { letter: 'D', text: 'satisfying' }], correct: 'A', explanation: '"Ambiguous" means open to multiple interpretations, matching an unresolved ending designed to create uncertainty.' },
  { id: 'sat_rw_b6_110', category: 'writing', subcategory: 'grammar', difficulty: 'hard', passage: 'Were the funding to ________ approved, the research team could begin clinical trials by the end of the year.', question: 'Which choice conforms to Standard English?', options: [{ letter: 'A', text: 'be' }, { letter: 'B', text: 'been' }, { letter: 'C', text: 'being' }, { letter: 'D', text: 'is' }], correct: 'A', explanation: 'In the inverted subjunctive conditional "Were the funding to be approved," the infinitive "be" is correct.' },
  { id: 'sat_rw_b6_111', category: 'reading', subcategory: 'reading-comprehension', difficulty: 'hard', passage: 'Proponents of nuclear energy argue that it produces minimal greenhouse gas emissions during operation and can generate vast quantities of electricity from a small physical footprint. Critics, however, point to the risks of catastrophic accidents, the unresolved problem of long-term radioactive waste storage, and the high costs of plant construction. Some analysts suggest that advances in small modular reactor technology could address many of these concerns while preserving nuclear power\'s low-carbon advantages.', question: 'The mention of small modular reactors serves to ________', options: [{ letter: 'A', text: 'suggest a potential compromise between the positions of proponents and critics' }, { letter: 'B', text: 'dismiss the concerns raised by nuclear energy critics' }, { letter: 'C', text: 'argue that traditional nuclear plants should be expanded' }, { letter: 'D', text: 'demonstrate that nuclear energy has no remaining drawbacks' }], correct: 'A', explanation: 'Small modular reactors are presented as potentially addressing critics\' concerns while keeping the low-carbon benefits proponents champion.' },
  { id: 'sat_rw_b6_112', category: 'writing', subcategory: 'sentence-structure', difficulty: 'hard', passage: 'The new medication reduced symptoms significantly in clinical trials. However, its long-term side effects remain unknown. The FDA has approved it only for short-term use.', question: 'Which choice best combines the second and third sentences?', options: [{ letter: 'A', text: 'Because its long-term side effects remain unknown, the FDA has approved it only for short-term use.' }, { letter: 'B', text: 'Its long-term side effects remain unknown, the FDA approved it for short-term use.' }, { letter: 'C', text: 'Unknown long-term side effects and short-term FDA approval were the result.' }, { letter: 'D', text: 'The FDA approved it for short-term use and long-term side effects remain unknown.' }], correct: 'A', explanation: '"Because" establishes the causal link between unknown side effects and the FDA\'s limited approval.' },
  { id: 'sat_rw_b6_113', category: 'reading', subcategory: 'vocabulary', difficulty: 'hard', passage: 'The author\'s critique of consumerism was ________; beneath the surface humor of her satirical essays lay a deeply serious indictment of materialism and waste.', question: 'Which word best completes the text?', options: [{ letter: 'A', text: 'trenchant' }, { letter: 'B', text: 'lighthearted' }, { letter: 'C', text: 'superficial' }, { letter: 'D', text: 'frivolous' }], correct: 'A', explanation: '"Trenchant" means incisive and forceful, fitting a critique with serious depth beneath its humor.' },
  { id: 'sat_rw_b6_114', category: 'writing', subcategory: 'grammar', difficulty: 'hard', passage: 'The findings of the study, which ________ peer-reviewed by three independent experts, were published in a leading scientific journal.', question: 'Which choice conforms to Standard English?', options: [{ letter: 'A', text: 'were' }, { letter: 'B', text: 'was' }, { letter: 'C', text: 'is' }, { letter: 'D', text: 'has been' }], correct: 'A', explanation: '"Which" refers to "findings" (plural), requiring the plural verb "were."' },
  { id: 'sat_rw_b6_115', category: 'writing', subcategory: 'punctuation', difficulty: 'hard', passage: 'The historian challenged a widely held assumption________ that the revolution was driven primarily by economic grievances________ by presenting evidence that ideological factors played an equally significant role.', question: 'Which punctuation correctly sets off the phrase?', options: [{ letter: 'A', text: '— ... —' }, { letter: 'B', text: ', ... ,' }, { letter: 'C', text: '; ... ;' }, { letter: 'D', text: ': ... :' }], correct: 'A', explanation: 'Em dashes set off the parenthetical clarification of what assumption is being challenged.' },
  { id: 'sat_rw_b6_116', category: 'reading', subcategory: 'reading-comprehension', difficulty: 'hard', passage: 'Epigenetics, the study of heritable changes in gene expression that do not involve alterations to the DNA sequence itself, has challenged the traditional view that evolution occurs only through genetic mutations. Research has shown that environmental factors such as diet and stress can produce epigenetic changes that are passed from one generation to the next. This suggests that organisms can, in a limited sense, pass on traits acquired during their lifetimes, a concept reminiscent of Lamarckian evolution, which mainstream biology had long dismissed.', question: 'The author\'s reference to Lamarckian evolution primarily serves to ________', options: [{ letter: 'A', text: 'highlight how epigenetics has revived aspects of a previously rejected theory' }, { letter: 'B', text: 'argue that Lamarck\'s theory was entirely correct' }, { letter: 'C', text: 'show that genetic mutations are no longer relevant to evolution' }, { letter: 'D', text: 'dismiss epigenetics as pseudoscience' }], correct: 'A', explanation: 'The passage notes epigenetic inheritance is "reminiscent of" Lamarck\'s dismissed concept, suggesting partial rehabilitation.' },
  { id: 'sat_rw_b6_117', category: 'writing', subcategory: 'sentence-structure', difficulty: 'hard', passage: 'Carefully analyzing each data point, ________.', question: 'Which choice correctly completes the sentence?', options: [{ letter: 'A', text: 'the statistician identified a significant trend in the results' }, { letter: 'B', text: 'a significant trend was identified in the results' }, { letter: 'C', text: 'the results showed a significant trend' }, { letter: 'D', text: 'it became clear that a trend existed' }], correct: 'A', explanation: 'The participial phrase must modify the person doing the analyzing: "the statistician."' },
  { id: 'sat_rw_b6_118', category: 'reading', subcategory: 'vocabulary', difficulty: 'hard', passage: 'The researcher\'s conclusions were ________; despite claiming to be objective, her analysis systematically favored data that supported her initial hypothesis while downplaying contradictory evidence.', question: 'Which word best completes the text?', options: [{ letter: 'A', text: 'tendentious' }, { letter: 'B', text: 'impartial' }, { letter: 'C', text: 'disinterested' }, { letter: 'D', text: 'unbiased' }], correct: 'A', explanation: '"Tendentious" means biased toward a particular viewpoint, matching the selective treatment of evidence described.' },
  { id: 'sat_rw_b6_119', category: 'writing', subcategory: 'grammar', difficulty: 'hard', passage: 'Neither the complexity of the subject matter nor the density of the technical language ________ an excuse for unclear writing.', question: 'Which choice conforms to Standard English?', options: [{ letter: 'A', text: 'is' }, { letter: 'B', text: 'are' }, { letter: 'C', text: 'were' }, { letter: 'D', text: 'have been' }], correct: 'A', explanation: 'With "neither...nor," the verb agrees with the nearer subject "density" (singular), requiring "is."' },
  { id: 'sat_rw_b6_120', category: 'reading', subcategory: 'reading-comprehension', difficulty: 'hard', passage: 'Game theory, originally developed to analyze competitive situations in economics, has found applications in fields as diverse as evolutionary biology and political science. In biology, researchers use game theory to model how organisms develop strategies for survival and reproduction. In political science, it helps explain why nations sometimes cooperate even when short-term self-interest would suggest defection. The theory\'s versatility stems from its focus on decision-making under conditions of interdependence, a feature common to many complex systems.', question: 'According to the passage, why has game theory been adopted across multiple disciplines?', options: [{ letter: 'A', text: 'Its focus on interdependent decision-making applies to many complex systems' }, { letter: 'B', text: 'It was specifically designed to be multidisciplinary' }, { letter: 'C', text: 'Economic models are identical to biological models' }, { letter: 'D', text: 'All academic fields require competitive analysis' }], correct: 'A', explanation: 'The passage states the theory\'s versatility comes from its focus on "decision-making under conditions of interdependence."' },
];
